class Färgmängd(set):

  def __str__(self):
    pass

def main():
  mängd = {"Vit",\
  "Gul", "Blå", "Grön"}

  print("Utskrift av 'set':")
  print(mängd)


  färgmängd = Färgmängd(set()) #För att skapa tomt set använd set()
  for element in mängd:
    färgmängd.add(element) # alla metoder som set har ärvs av Färgmängd
  print("Utskrift av 'Färgmängd':")
  print(färgmängd)


main()
